import queue
import threading
import requests

_SENTINEL = object()


class RemoteLogSink:
    def __init__(self, endpoint: str, max_queue: int = 10_000):
        self._endpoint = endpoint
        self._q: queue.Queue = queue.Queue(maxsize=max_queue)
        self._thread = threading.Thread(target=self._drain, daemon=True)
        self._thread.start()

    def emit(self, record: dict):
        try:
            self._q.put_nowait(record)  # non-blocking; drop if full
        except queue.Full:
            pass  # drop rather than block the caller

    def _drain(self):
        session = requests.Session()
        while True:
            record = self._q.get()
            if record is _SENTINEL:
                break
            try:
                session.post(self._endpoint, json=record, timeout=5)
            except Exception:
                pass  # swallow — never let the sink crash the app

    def close(self):
        self._q.put(_SENTINEL)
        self._thread.join(timeout=5)


# Usage:
sink = RemoteLogSink("https://logs.example.com/ingest")
# In your wrapper, replace logger.info(...) with:
# sink.emit({"event": "claude.create", ...})
# At shutdown:
import atexit
atexit.register(sink.close)
